parameters.jsCode:
const response = $input.first().json.choices[0].message.content;
try {
  let script;
  try { script = JSON.parse(response); }
  catch {
    const jsonMatch = response.match(/```(?:json)?\n?([\s\S]*?)\n?```/) || response.match(/(\{[\s\S]*\})/);
    if (!jsonMatch) throw new Error('No JSON found');
    script = JSON.parse(jsonMatch[1] || jsonMatch[0]);
  }
  const webhookData = $('Webhook - Video Request').first().json.body;
  return [{ json: {
    ...script,
    video_id: webhookData.video_id,
    user_id: webhookData.user_id,
    voice_id: webhookData.voice_id || 'nb-NO-PernilleNeural',
    platform: webhookData.platform || 'tiktok',
    language: webhookData.language || 'nb',
    aspect_ratio: webhookData.aspect_ratio || '9:16',
    target_audience: webhookData.target_audience || 'general',
  }}];
} catch(e) { throw new Error('Parse script failed: ' + e.message); }

const item = items[0].json;
const voiceId = item.voice_id || 'nb-NO-PernilleNeural';
const tts_voice = voiceId.endsWith('Neural') ? voiceId : voiceId + 'Neural';
return [{ json: { ...item, tts_voice } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const voice = item.tts_voice || 'nb-NO-PernilleNeural';

let rawText = '';
if (item.scenes && Array.isArray(item.scenes) && item.scenes.length > 0) {
  rawText = item.scenes.map(s => s.narration || '').filter(Boolean).join('. ');
} else {
  rawText = item.topic || item.title || 'VideoMill produksjon';
}

const cleanText = rawText.replace(/["'`$\]/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 2000);

const dir = `/workspace/video_assets/${videoId}`;
const outputPath = `${dir}/voiceover.mp3`;

try {
  execSync(`mkdir -p ${dir}`, { shell: '/bin/bash' });
  execSync(`edge-tts --voice "${voice}" --text "${cleanText}" --write-media "${outputPath}"`, {
    encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
  return [{ json: { ...item, voiceover_path: outputPath, engine_status: 'success', voice_used: voice } }];
} catch (err) { throw new Error('Voiceover feilet: ' + err.message); }

const item = items[0].json;
const scenes = item.scenes || [];
const videoId = item.video_id;

return scenes.map((scene, index) => ({
  json: {
    ...item,
    video_id: videoId,
    scene,
    batchIndex: index,
    duration_seconds: scene.duration_seconds || 5,
    search_query: (scene.search_keywords && scene.search_keywords[0]) || item.topic || 'nature',
  }
}));


const item = items[0].json;
const scenes = item.scenes || [];
const videoId = item.video_id || $('Webhook - Video Request').first().json.body.video_id;

return scenes.map((scene, index) => ({
  json: {
    ...item,
    video_id: videoId,
    scene,
    batchIndex: index,
    duration_seconds: scene.duration_seconds || 5,
    search_query: (scene.search_keywords && scene.search_keywords[0]) || item.topic || 'nature',
  }
}));

const videos = $input.first().json.videos || [];
if (!videos.length) return [{ json: { clip_url: null } }];
const best = videos[0];
const hdFile = best.video_files.find(f => f.quality === 'hd') || best.video_files.find(f => f.quality === 'sd') || best.video_files[0];
return [{ json: { clip_url: hdFile.link, clip_id: best.id } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const clipUrl = item.clip_url;
const batchIndex = item.batchIndex || 0;
const duration = item.duration_seconds || 5;
const dir = `/workspace/video_assets/${videoId}`;

execSync(`mkdir -p ${dir}/clips`, { shell: '/bin/bash' });

if (!clipUrl) {
  const cmd = `ffmpeg -y -f lavfi -i color=c=black:size=1080x1920:rate=30 -t ${duration} -c:v libx264 -preset fast ${dir}/clips/scene_${batchIndex}.mp4`;
  execSync(cmd, { encoding: 'utf-8', timeout: 120000, shell: '/bin/bash' });
  return [{ json: { ...item, video_id: videoId, clip_path: `${dir}/clips/scene_${batchIndex}.mp4`, success: true } }];
}

const cmd = `ffmpeg -y -i "${clipUrl}" -t ${duration} -c:v libx264 -preset fast -an "${dir}/clips/scene_${batchIndex}.mp4"`;
execSync(cmd, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
return [{ json: { ...item, video_id: videoId, clip_path: `${dir}/clips/scene_${batchIndex}.mp4`, success: true } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id || $('Webhook - Video Request').first().json.body.video_id;
const dir = `/workspace/video_assets/${videoId}`;

execSync(`mkdir -p ${dir}/clips`, { shell: '/bin/bash' });

const files = execSync(`ls ${dir}/clips/scene_*.mp4 2>/dev/null || echo ''`, { encoding: 'utf-8', shell: '/bin/bash' }).trim();
if (!files) throw new Error('Ingen scene-filer funnet');

const cmd = `cd ${dir}/clips && ls scene_*.mp4 | sort -V | sed "s/^/file '/;s/$/'/" > filelist.txt && ffmpeg -y -f concat -safe 0 -i filelist.txt -c:v libx264 -preset fast "${dir}/concat.mp4"`;
execSync(cmd, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
return [{ json: { ...item, video_id: videoId, concat_path: `${dir}/concat.mp4`, success: true } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const dir = `/workspace/video_assets/${videoId}`;

execSync(`mkdir -p ${dir}`, { shell: '/bin/bash' });
execSync(`ffmpeg -y -i "${dir}/concat.mp4" -i "${dir}/voiceover.mp3" -c:v copy -c:a aac -shortest "${dir}/final_16x9.mp4"`, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
return [{ json: { ...item, video_id: videoId, master_path: `${dir}/final_16x9.mp4` } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const dir = `/workspace/video_assets/${videoId}`;
const ratio = item.aspect_ratio || '9:16';

if (ratio === '9:16' || ratio !== '16:9') {
  execSync(`ffmpeg -y -i "${dir}/final_16x9.mp4" -vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2,setsar=1" "${dir}/final_9x16.mp4"`, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
}
execSync(`ffmpeg -y -i "${dir}/final_16x9.mp4" -vf "scale=1080:1080:force_original_aspect_ratio=decrease,pad=1080:1080:(ow-iw)/2:(oh-ih)/2,setsar=1" "${dir}/final_1x1.mp4"`, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
return [{ json: { ...item, video_id: videoId, success: true } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const userId = item.user_id;
const dir = `/workspace/video_assets/${videoId}`;
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;

const uploads = [
  { file: 'final_16x9.mp4', format: '16x9' },
  { file: 'final_9x16.mp4', format: '9x16' },
  { file: 'final_1x1.mp4', format: '1x1' },
];

const uploadedUrls = {};
for (const u of uploads) {
  const filePath = `${dir}/${u.file}`;
  const storagePath = `${userId}/${videoId}/${u.file}`;
  try {
    execSync(`curl -sf -X POST "${supabaseUrl}/storage/v1/object/videos/${storagePath}" -H "Authorization: Bearer ${serviceKey}" -H "Content-Type: video/mp4" --data-binary @"${filePath}"`, { encoding: 'utf-8', timeout: 600000, shell: '/bin/bash' });
    uploadedUrls[`video_url_${u.format.replace(':','x')}`] = `${supabaseUrl}/storage/v1/object/public/videos/${storagePath}`;
  } catch(err) { console.log('Upload failed: ' + err.message); }
}
return [{ json: { ...item, video_id: videoId, user_id: userId, ...uploadedUrls } }];

const { execSync } = require('child_process');
const videoId = items[0].json.video_id;
try {
  execSync(`rm -rf /workspace/video_assets/${videoId}`, { encoding: 'utf-8', timeout: 30000, shell: '/bin/bash' });
  return [{ json: { ...items[0].json, cleanup: 'done' } }];
} catch (err) { return [{ json: { ...items[0].json, cleanup: 'failed' } }]; }

const resp = $input.first().json.response || '';
let topics = [];
try { topics = JSON.parse(resp); }
catch { try { const match = resp.match(/\[[\s\S]*\]/); if (match) topics = JSON.parse(match[0]); } catch(e) { throw new Error('Parse failed'); } }

const platformByCategory = { tech: 'youtube', motivation: 'tiktok', history: 'youtube', science: 'youtube', crime: 'tiktok', finance: 'youtube', health: 'instagram', mystery: 'tiktok' };

return topics.map(t => ({ json: {
  title: t.title || 'Ukjent',
  category: t.category || 'general',
  viral_score: t.rank || Math.floor(Math.random() * 40 + 55),
  heat_level: t.heat || 'rising',
  growth_stat: t.reason || null,
  tags: Array.isArray(t.tags) ? t.tags : [],
  platform: t.platform || platformByCategory[t.category] || 'youtube',
  target_audience: t.target_audience || 'General audience',
} }));

